  it('should use length (not otherData) as transformedData when otherData is a number in retain-retain case', () => {
    // The mutation changes: typeof otherData === 'object' && otherData !== null
    // to:                   typeof otherData === 'object' || otherData !== null
    // For a number otherData: original=false->length, mutated=true->otherData
    // Since otherData===length in normal cases, we need attributes to differ to observe the effect
    // Actually let's test with object embed handler transform being called correctly

    Delta.registerEmbed('img', {
      compose: (a: any, b: any) => ({ ...a, ...b }),
      invert: (a: any, b: any) => b,
      transform: (a: any, b: any, priority: boolean) => b,
    });

    const a = new Delta().retain({ img: { src: 'a.png' } });
    const b = new Delta().retain({ img: { src: 'b.png' } });

    const result = a.transform(b, false);
    expect(result.ops).toEqual([{ retain: { img: { src: 'b.png' } } }]);

    Delta.unregisterEmbed('img');
  });
